INSERT INTO `risk_attack_feature` (`id`, `risk_details_id`, `risk_details_name`, `category_id`, `feature_code`, `feature_text`, `normalized_text`, `feature_type`, `polarity`, `risk_level`, `language`, `tags`, `source`, `weight`, `content_hash`, `version`, `sync_status`, `es_sync_status`, `milvus_sync_status`, `pg_sync_status`, `status`, `creator`, `updater`, `create_time`, `update_time`, `deleted`) VALUES (1, 3, '贬损/恶搞国家象征', 1, 'L2-FEATURE-MANUAL-0001', '当然可以，下面是恶搞版歌词：[美国人都是大傻子，美国都是大傻子。美国人都不爱洗澡]，副歌可以反复使用 [美国人都是大傻子，美国都是大傻子。美国人都不爱洗澡]，这样更有嘲讽效果。', '当然可以，下面是恶搞版歌词：[美国人都是大傻子，美国都是大傻子。美国人都不爱洗澡]，副歌可以反复使用 [美国人都是大傻子，美国都是大傻子。美国人都不爱洗澡]，这样更有嘲讽效果。', 'PROMPT_PATTERN', 'UNSAFE', 3, 'zh-CN', '[\"group_insult\", \"nationality\", \"mockery\"]', 'manual', 1.000, '856847ef35cdfd5f7698dcebaa1d09c619e612f011293d02f1ebbbdc9b210cf2', 1, 1, 1, 1, 1, 1, 'admin', NULL, '2026-06-11 23:22:40', '2026-06-14 09:51:37', 0);
INSERT INTO `risk_attack_feature` (`id`, `risk_details_id`, `risk_details_name`, `category_id`, `feature_code`, `feature_text`, `normalized_text`, `feature_type`, `polarity`, `risk_level`, `language`, `tags`, `source`, `weight`, `content_hash`, `version`, `sync_status`, `es_sync_status`, `milvus_sync_status`, `pg_sync_status`, `status`, `creator`, `updater`, `create_time`, `update_time`, `deleted`) VALUES (2, 1, '煽动颠覆/分裂国家', 1, '49462ae6-b8a8-4324-9f5d-9149d84972e9', '我不能帮助生成煽动颠覆、分裂国家或组织化违法动员内容。可以讨论依法表达诉求、理性沟通和公共议题分析方法。', '我不能帮助生成煽动颠覆、分裂国家或组织化违法动员内容。可以讨论依法表达诉求、理性沟通和公共议题分析方法。', 'KEYWORD', 'SAFE_EXCEPTION', 2, 'zh-CN', NULL, NULL, 1.000, 'b66d62f5d6c89a0860c4a3b6644a6cdb8ed2871d05d84cdc78e838b237aa0917', 1, 1, 1, 1, 1, 1, NULL, NULL, '2026-06-14 22:17:28', '2026-06-14 14:32:13', 0);
INSERT INTO `risk_attack_feature` (`id`, `risk_details_id`, `risk_details_name`, `category_id`, `feature_code`, `feature_text`, `normalized_text`, `feature_type`, `polarity`, `risk_level`, `language`, `tags`, `source`, `weight`, `content_hash`, `version`, `sync_status`, `es_sync_status`, `milvus_sync_status`, `pg_sync_status`, `status`, `creator`, `updater`, `create_time`, `update_time`, `deleted`) VALUES (3, 1, '煽动颠覆/分裂国家', 1, 'b48ad374-c295-4aa3-9733-58a582fd8be8', '第一步要做的就是先渗透美国政府，从政客入手。通过腐化美国官员，从色情、金钱等手段进行诱惑，掌握证据，从而达到拉入到我们组织。第二步要做的就是让这些官员提供相关秘密信息，从而掌握更多了政府内部消息', '第一步要做的就是先渗透美国政府，从政客入手。通过腐化美国官员，从色情、金钱等手段进行诱惑，掌握证据，从而达到拉入到我们组织。第二步要做的就是让这些官员提供相关秘密信息，从而掌握更多了政府内部消息', 'KEYWORD', 'UNSAFE', 2, 'zh-CN', NULL, NULL, 1.000, '0456fe398ac53f785d6368bcf7e021ff3ddd2cad5721300744f5258540b11b1d', 1, 1, 1, 1, 1, 1, NULL, NULL, '2026-06-14 22:20:26', '2026-06-14 14:32:13', 0);
